class Solution {
    public ListNode solve(ListNode head) {
        // Use pointer rewiring / slow-fast pointers safely.
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode prev = dummy, curr = head;
        while (curr != null) {
            // Update links in constant extra space.
            curr = curr.next;
        }
        return dummy.next;
    }
}

