find-median-from-data-stream.java_pseudocode:
class Solution {
    public int solve(int[] nums, int k) {
        // Keep a size-k heap for top-k style problems.
        PriorityQueue<Integer> heap = new PriorityQueue<>();
        for (int value : nums) {
            heap.offer(value);
            if (heap.size() > k) heap.poll();
        }
        return heap.peek();
    }
}

