class Solution {
    public int solve(int[] nums) {
        // Use stack to preserve monotonic / structural invariant.
        Deque<Integer> stack = new ArrayDeque<>();
        int answer = 0;
        for (int value : nums) {
            while (!stack.isEmpty() && shouldPop(stack.peek(), value)) {
                // Resolve work for popped index/value.
                stack.pop();
            }
            stack.push(value);
        }
        return answer;
    }
}

