            } else {
                lo = mid + 1;
            }
        }
        return lo;
    }
}

subtree-of-another-tree.java_pseudocode:
class Solution {
    public int solve(TreeNode root) {
        // DFS returns sub-result; combine on unwind.
        return dfs(root);
    }

    private int dfs(TreeNode node) {
        if (node == null) return 0;
        int left = dfs(node.left);
        int right = dfs(node.right);
        // Merge left/right child answers with current node.
        return combine(node, left, right);
    }
}

design-add-and-search-words-data-structu.java_pseudocode:
class Trie {
    private static class Node {
        Node[] next = new Node[26];
        boolean end;
    }
    private final Node root = new Node();

    public void insert(String word) {
        Node cur = root;
        for (char ch : word.toCharArray()) {
            int idx = ch - 'a';
            if (cur.next[idx] == null) cur.next[idx] = new Node();
            cur = cur.next[idx];
        }
        cur.end = true;
    }
}

